describe('AdminProducts integration', () => {
  it('renders page heading and all products', () => {
    render(<AdminProducts />);

    expect(screen.getByRole('heading', { level: 1, name: 'Panel de productos' })).toBeInTheDocument();
    expect(screen.getByTestId('product-card-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-card-2')).toBeInTheDocument();
  });

  it('search input filters the product list', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    const searchInput = screen.getByRole('searchbox');
    await user.type(searchInput, 'auriculares');

    // Only card-1 should remain in filtered list
    expect(screen.getByTestId('product-card-1')).toBeInTheDocument();
    expect(screen.queryByTestId('product-card-2')).not.toBeInTheDocument();
  });

  it('search is accent-insensitive and can be cleared with Escape', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    const searchInput = screen.getByRole('searchbox');
    await user.type(searchInput, 'inalambricos');

    expect(screen.getByTestId('product-card-1')).toBeInTheDocument();
    expect(screen.queryByTestId('product-card-2')).not.toBeInTheDocument();

    await user.keyboard('{Escape}');

    expect(searchInput).toHaveValue('');
    expect(screen.getByTestId('product-card-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-card-2')).toBeInTheDocument();
    expect(searchInput).toHaveAttribute('aria-describedby', 'admin-products-search-shortcut');
    expect(screen.getByText('Atajos: / para enfocar búsqueda y Escape para limpiar.')).toBeInTheDocument();
  });

  it('pressing slash focuses product search when not typing in another field', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    const pageTitle = screen.getByRole('heading', { level: 1, name: 'Panel de productos' });
    const searchInput = screen.getByRole('searchbox');

    pageTitle.focus();
    expect(searchInput).not.toHaveFocus();

    await user.keyboard('/');

    expect(searchInput).toHaveFocus();
  });

  it('clear search button appears and restores full list when clicked', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    await user.type(screen.getByRole('searchbox'), 'auriculares');

    const clearButton = screen.getByRole('button', { name: 'Limpiar búsqueda' });
    expect(clearButton).toBeInTheDocument();

    await user.click(clearButton);

    expect(screen.queryByRole('button', { name: 'Limpiar búsqueda' })).not.toBeInTheDocument();
    expect(screen.getByTestId('product-card-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-card-2')).toBeInTheDocument();
  });

  it('clicking Edit fills the form with product data', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    const editBtn = within(screen.getByTestId('product-card-1')).getByRole('button', { name: 'Editar' });
    await user.click(editBtn);

    // Heading should switch to "Editar producto"
    expect(screen.getByRole('heading', { level: 2, name: 'Editar producto' })).toBeInTheDocument();

    // Form fields should be pre-filled
    expect(screen.getByDisplayValue('Auriculares Bluetooth')).toBeInTheDocument();
    expect(screen.getByDisplayValue('59.99')).toBeInTheDocument();
    expect(screen.getByDisplayValue('Electronica')).toBeInTheDocument();
  });

  it('form submit calls addProduct for a new product', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    await user.type(screen.getByLabelText('Nombre'), 'Nuevo Producto');
    await user.type(screen.getByLabelText('Precio'), '19.99');
    await user.type(screen.getByLabelText('Categoría'), 'Libros');
    await user.type(screen.getByLabelText('Descripción'), 'Una descripción.');

    await user.click(screen.getByRole('button', { name: 'Crear producto' }));

    expect(mockAddProduct).toHaveBeenCalledOnce();
    expect(mockShowToast).toHaveBeenCalledWith('Producto creado.', 'success');
  });

  it('clicking Cancel edit resets the form to create mode', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    // Enter edit mode
    await user.click(within(screen.getByTestId('product-card-1')).getByRole('button', { name: 'Editar' }));
    expect(screen.getByRole('heading', { level: 2, name: 'Editar producto' })).toBeInTheDocument();

    // Cancel edit
    await user.click(screen.getByRole('button', { name: 'Cancelar edición' }));
    expect(screen.getByRole('heading', { level: 2, name: 'Añadir producto' })).toBeInTheDocument();
  });

  it('delete opens ConfirmDialog and executes delete on confirm', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    const deleteBtn = within(screen.getByTestId('product-card-1')).getByRole('button', { name: 'Eliminar' });
    await user.click(deleteBtn);

    // ConfirmDialog should appear
    const dialog = screen.getByRole('dialog');
    expect(dialog).toBeInTheDocument();

    // Confirm deletion
    await user.click(within(dialog).getByRole('button', { name: 'Eliminar' }));

    expect(mockDeleteProduct).toHaveBeenCalledWith(1);
    expect(mockRemoveProductReferences).toHaveBeenCalledWith(1);
    expect(mockShowToast).toHaveBeenCalledWith('Producto eliminado.', 'info');
  });

  it('cancelling the ConfirmDialog does not delete the product', async () => {
    const user = userEvent.setup();
    render(<AdminProducts />);

    await user.click(within(screen.getByTestId('product-card-1')).getByRole('button', { name: 'Eliminar' }));

    const dialog = screen.getByRole('dialog');
    await user.click(within(dialog).getByRole('button', { name: 'Cancelar' }));

    expect(mockDeleteProduct).not.toHaveBeenCalled();
    expect(screen.queryByRole('dialog')).not.toBeInTheDocument();
  });
});
